function wfMatHtml(wf){wf=wf||{};var fs=(wf.dataFiles&&wf.dataFiles.length)?wf.dataFiles:(wf.dataUrl?[{name:"제출 파일",url:wf.dataUrl}]:[]);if(!fs.length&&!wf.dataLink)return "";var h='<div class="bg-g50 rounded-2xl p-3.5 mb-3 text-[13px]"><p class="font-bold text-g700 mb-1.5">고객 제출 자료</p>';for(var i=0;i<fs.length;i++){h+='<button onclick="openLink(&#39;'+esc(fs[i].url)+'&#39;)" class="block text-left text-blue font-bold underline mb-1 break-all">📎 '+esc(fs[i].name||("파일 "+(i+1)))+' ↗</button>';}if(wf.dataLink)h+='<p class="text-g600 whitespace-pre-wrap mt-1">'+esc(wf.dataLink)+'</p>';h+='</div>';return h;}
function custMatHtml(wf){wf=wf||{};var fs=(wf.dataFiles&&wf.dataFiles.length)?wf.dataFiles:(wf.dataUrl?[{name:"제출 파일",url:wf.dataUrl}]:[]);if(!fs.length&&!wf.dataLink)return "";var h='<div class="bg-g50 rounded-2xl p-3.5 text-[13px]"><p class="font-bold text-g700 mb-1.5">제출한 자료</p>';for(var i=0;i<fs.length;i++){h+='<button onclick="openLink(&#39;'+esc(fs[i].url)+'&#39;)" class="block text-left text-blue font-bold underline mb-1 break-all">📎 '+esc(fs[i].name||("파일 "+(i+1)))+' ↗</button>';}if(wf.dataLink)h+='<p class="text-g600 whitespace-pre-wrap mt-1">'+esc(wf.dataLink)+'</p>';h+='<p class="text-g500 mt-1.5">크놀AD 확인 후 다음 단계가 진행됩니다 · 추가 자료는 아래에서 다시 제출할 수 있어요</p></div>';return h;}
function wfTypeBadge(c){return isSimpleWf(c)?'<span class="text-[11px] font-bold px-2 py-0.5 rounded-lg bg-amber-50 text-amber-600 ml-1.5 align-middle">단순업로드</span>':'<span class="text-[11px] font-bold px-2 py-0.5 rounded-lg bg-blue-tint text-blue ml-1.5 align-middle">제작</span>';}
function simpleStageIdx(wf){var s=(wf&&wf.step)||2;if(s>=7)return 5;if(s>=5)return 4;if(s>=3)return 3;return (wf&&wf.dataUrl)?3:2;}
function simpleStepperHtml(camp){var wf=(typeof wfOf==="function")?wfOf(camp):((camp&&camp.wf)||{step:2});var step=simpleStageIdx(wf);var S=[["문의","message-circle"],["영상 접수","upload"],["영상 검수","badge-check"],["업로드","clapperboard"],["완료","party-popper"]];var N=S.length;return `<div class="overflow-x-auto"><div class="flex items-center justify-between py-6 px-4" style="min-width:520px">${S.map(function(st,i){var idx=i+1,done=idx<step,act=idx===step;return (i>0?`<div class="h-[3px] flex-1 min-w-[14px] mx-1 rounded-full ${idx<step||step>=N?"bg-blue":idx===step?"bg-blue/40":"bg-g200"}"></div>`:"")+`<div class="flex flex-col items-center gap-1.5 flex-shrink-0"><div class="w-12 h-12 rounded-full grid place-items-center flex-shrink-0 ${done||act?"text-white":"bg-white text-g400 border-2 border-g200"}${act?" wf-glow":""}" ${done?'style="background:#10b981"':act?'style="background:#3182F6"':""}>${done?'<i data-lucide="check" class="w-6 h-6"></i>':`<i data-lucide="${st[1]}" class="w-6 h-6"></i>`}</div><span class="text-[15px] font-bold whitespace-nowrap ${act?"text-blue":done?"text-g700":"text-g400"}">${st[0]}</span></div>`;}).join("")}</div></div>`;}
function simpleCustPanel(wf,cur){if(cur<=2)return `<div class="space-y-3">${custMatHtml(wf)}${uploadZone("wfData","업로드할 완성 영상 파일")}<textarea id="wfRef" rows="3" placeholder="영상 링크 또는 전달할 내용 (요청사항·메모)" class="${INPUT} resize-none"></textarea><button onclick="wfDataSubmit()" class="${BTN} w-full">영상 제출 →</button><p class="text-[13px] text-g500 text-center">단순업로드 캠페인 · 콘티/컨펌 없이 크놀AD 검수 후 바로 업로드됩니다</p></div>`;if(cur<5)return `<div class="text-center py-6 px-4 border border-g200 rounded-2xl bg-g50"><div class="w-16 h-16 rounded-full bg-blue-tint grid place-items-center mx-auto mb-3"><i data-lucide="badge-check" class="w-8 h-8 text-blue"></i></div><p class="text-[23px] font-bold text-g900 mb-1.5">크놀AD가 영상을 검수하고 있어요!</p><p class="text-[16px] text-g500">이상이 없으면 바로 업로드가 진행됩니다 ⏳</p></div>`;return `<div class="text-center py-6 px-4 border border-g200 rounded-2xl bg-g50"><div class="w-16 h-16 rounded-full bg-blue-tint grid place-items-center mx-auto mb-3"><i data-lucide="clapperboard" class="w-8 h-8 text-blue"></i></div><p class="text-[23px] font-bold text-g900 mb-1.5">검수 완료 · 업로드를 진행하고 있어요!</p><p class="text-[16px] text-g500">업로드가 끝나면 완료로 표시됩니다 ⏳</p></div>`;}
function admSimplePanel(a,wf,u,mat){var st=(wf&&wf.step)||2;if(st<5)return `${mat||""}<div class="bg-g50 rounded-2xl p-4 text-[14px] text-g600 mb-3">단순업로드 캠페인입니다. 고객이 전달한 영상을 검수하고, 이상이 없으면 업로드 단계로 넘기세요. (콘티·컨펌 단계 없음)</div><button onclick="admWfSave('${a.id}',{step:5},'영상 검수 완료 · 업로드를 진행합니다')" class="${BTN} w-full">영상 검수 완료 → 업로드 진행</button>`;if(st<7)return `<p class="text-[14px] font-bold text-g700 mb-2">업로드 URL 입력 후 완료 처리</p><input id="admYt" placeholder="YouTube URL" value="${esc(u.yt||"")}" class="${INPUT} mb-2"><input id="admIg" placeholder="Instagram URL" value="${esc(u.ig||"")}" class="${INPUT} mb-2"><input id="admTt" placeholder="TikTok URL" value="${esc(u.tt||"")}" class="${INPUT} mb-2"><button onclick="admSaveUrls('${a.id}')" class="${BTN_GHOST} w-full mb-2">업로드 URL 저장</button><button onclick="admWfSave('${a.id}',{step:7},'업로드가 완료되었습니다')" class="${BTN} w-full">업로드 완료 처리 →</button>`;return `<div class="bg-emerald-50 rounded-2xl p-3 text-[14px] text-emerald-700 font-bold text-center mb-2">업로드 완료된 캠페인입니다 🎉</div><input id="admYt" placeholder="YouTube URL" value="${esc(u.yt||"")}" class="${INPUT} mb-2"><input id="admIg" placeholder="Instagram URL" value="${esc(u.ig||"")}" class="${INPUT} mb-2"><input id="admTt" placeholder="TikTok URL" value="${esc(u.tt||"")}" class="${INPUT} mb-2"><button onclick="admSaveUrls('${a.id}')" class="${BTN_GHOST} w-full">업로드 URL 저장</button>`;}
