if(wf.video){var dv=asDeliver(wf.video);ev.push({ic:"clapperboard",who:"크놀AD",t:"영상 전달"+(dv.title?" · "+dv.title:""),c:"violet",note:dv.text,fileUrl:dv.fileUrl,link:dv.link});}
if(wf.step>=7)ev.push({ic:"check",who:"고객",t:"영상 컨펌 완료",c:"emerald"});
const u=wf.urls||{};if(u.yt||u.ig||u.tt)ev.push({ic:"bar-chart-3",who:"크놀AD",t:"업로드 완료 · 리포트에서 성과 확인",c:"blue",report:true});
