function ytId(u){if(!u)return null;const m=u.match(/(?:v=|youtu\.be\/|shorts\/|embed\/)([A-Za-z0-9_-]{6,})/);return m?m[1]:null;}
function openReport(id){S.reportCamp=id;render();}function closeReport(){S.reportCamp=null;render();}function reportFolders(camps){var head=pageHeader("REPORT","인사이트 리포트","캠페인 폴더를 선택하세요");var f=camps.map(function(a){var w=wfOf(a),u=(w&&w.urls)||{},n=[u.yt,u.ig,u.tt].filter(Boolean).length;return `<button onclick="openReport('${a.id}')" class="${CARD} p-5 flex items-center gap-3 text-left hover:shadow-md transition-all"><div class="w-12 h-12 rounded-2xl bg-blue-tint grid place-items-center flex-shrink-0"><i data-lucide="folder" class="w-6 h-6 text-blue"></i></div><div class="min-w-0"><p class="text-[16px] font-bold text-g900 truncate">${esc(a.brand_name||"캠페인")}</p><p class="text-[13px] text-g500">링크 ${n}개</p></div></button>`;}).join("");return `<div class="p-8 md:p-10">${head}<div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-3 max-w-3xl">${f}</div></div>`;}function viewReport(){var _camps=(S.myCamps||[]).filter(function(a){return a.status==="승인 완료";});if(!S.reportCamp&&_camps.length){return reportFolders(_camps);}const c=S.reportCamp?(_camps.find(function(a){return String(a.id)===String(S.reportCamp);})||S.activeCamp):S.activeCamp;const wf=c?wfOf(c):{};const urls=wf.urls||{};const list=[["YouTube",urls.yt,"text-red-500"],["Instagram",urls.ig,"text-pink-500"],["TikTok",urls.tt,"text-g800"]].filter(x=>x[1]);
const head=pageHeader("REPORT","인사이트 리포트",c?esc(c.brand_name)+" 캠페인":"")+(S.reportCamp?`<button onclick="closeReport()" class="inline-flex items-center gap-1 text-[14px] font-bold text-g500 mb-4"><i data-lucide="arrow-left" class="w-4 h-4"></i>캠페인 목록</button>`:"");
if(!list.length)return `<div class="p-8 md:p-10">${head}<div class="max-w-xl"><div class="${CARD} p-14 text-center"><div class="w-14 h-14 rounded-[20px] bg-g100 grid place-items-center mx-auto mb-5"><i data-lucide="bar-chart-3" class="w-7 h-7 text-g300"></i></div><p class="text-[18px] font-bold text-g900 mb-1.5">업로드 완료 후 리포트가 제공됩니다</p><p class="text-[16px] text-g500 mb-5">크놀AD가 영상을 업로드하면 영상 URL·썸네일·조회수 인사이트가 여기에 표시됩니다.</p><div class="inline-flex items-center gap-2 px-3.5 py-1.5 rounded-full bg-amber-50"><i data-lucide="clock" class="w-3.5 h-3.5 text-amber-600"></i><span class="text-[15px] font-bold text-amber-700">업로드 대기중</span></div></div></div><p class="text-[13px] text-g500 mt-4 leading-relaxed max-w-3xl">※ 틱톡·인스타그램 미러링 업로드는 서비스로 제공되는 항목으로, 영상 링크만 전달되며 인사이트는 별도 제공되지 않습니다.</p></div>`;
const cards=list.map(x=>{const vid=x[0]==="YouTube"?ytId(x[1]):null;const thumb=vid?`<img src="https://i.ytimg.com/vi/${vid}/hqdefault.jpg" referrerpolicy="no-referrer" class="w-full aspect-video object-cover rounded-2xl mb-3" onerror="this.style.display='none'">`:`<div class="w-full aspect-video bg-g100 rounded-2xl mb-3 grid place-items-center text-g400"><i data-lucide="play-circle" class="w-10 h-10"></i></div>`;
return `<div class="${CARD} p-5">${thumb}<div class="flex items-center justify-between mb-3"><span class="font-bold ${x[2]}">${x[0]}</span><button onclick="openLink('${esc(x[1])}')" class="text-blue text-[13px] font-bold">영상 열기 ↗</button></div><p class="text-[12px] text-g400 truncate -mt-1 mb-3">${esc(x[1])}</p><div class="grid grid-cols-3 gap-2">${[["조회수","—"],["좋아요","—"],["댓글","—"]].map(sx=>`<div class="bg-g50 rounded-xl p-3 text-center"><p class="text-[12px] text-g400">${sx[0]}</p><p class="text-[18px] font-bold text-g900 num">${sx[1]}</p></div>`).join("")}</div><p class="text-[12px] text-g500 mt-2">* 조회수·시청자 인사이트는 추후 API 뷰어 연동 시 자동 표기됩니다.</p></div>`;}).join("");
return `<div class="p-8 md:p-10">${head}<div class="grid md:grid-cols-2 gap-4 max-w-3xl">${cards}</div><p class="text-[13px] text-g500 mt-4 leading-relaxed max-w-3xl">※ 틱톡·인스타그램 미러링 업로드는 서비스로 제공되는 항목으로, 영상 링크만 전달되며 인사이트는 별도 제공되지 않습니다.</p></div>`;}


function viewCalendar(){setTimeout(loadMyCamps,30);const nd=new Date();if(S.calY==null){S.calY=nd.getFullYear();S.calM=nd.getMonth();}const y=S.calY,m=S.calM;
const startDow=new Date(y,m,1).getDay();const days=new Date(y,m+1,0).getDate();const todayStr=`${nd.getFullYear()}-${String(nd.getMonth()+1).padStart(2,'0')}-${String(nd.getDate()).padStart(2,'0')}`;
const ev=[];(S.myCamps||[]).forEach(a=>{if(a.preferred_date)[].push({date:a.preferred_date,title:(a.brand_name||'')+" 업로드",type:"auto",campId:a.id});});
const sch=(S.activeCamp&&S.activeCamp.schedule)||[];sch.forEach(e=>ev.push({date:e.date,title:e.title,type:"manual",id:e.id}));
let cells="";for(let i=0;i<startDow;i++)cells+='<div></div>';
for(let d=1;d<=days;d++){const ds=`${y}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;const isT=ds===todayStr;const es=ev.filter(e=>e.date===ds);
cells+=`<div onclick="calAdd('${ds}')" class="min-h-[120px] md:min-h-[140px] border ${isT?'border-blue bg-blue-soft':'border-g100'} rounded-2xl p-2.5 cursor-pointer hover:bg-g50 transition-colors"><div class="text-[15px] font-bold ${isT?'text-blue':'text-g500'} mb-1">${d}</div>${es.map(e=>`<div onclick="event.stopPropagation();${e.type==='manual'?`calEdit('${e.id}')`:`calEditAuto('${e.campId}')`}" class="mb-1 text-[12px] px-2 py-1 rounded-lg ${e.type==='auto'?'bg-blue-tint text-blue':'bg-emerald-50 text-emerald-700'} truncate font-bold">${esc(e.title)}</div>`).join("")}</div>`;}
return `<div class="p-8 md:p-10">${pageHeader("SCHEDULE","캠페인 일정","업로드 일정은 담당 매니저가 등록·관리합니다 (보기 전용)")}
<div class="${CARD} p-6 md:p-8"><div class="flex items-center justify-between mb-5"><button onclick="calPrev()" class="w-10 h-10 rounded-full bg-g100 grid place-items-center text-g600 hover:bg-g200 text-[18px] font-bold">‹</button><h2 class="text-[22px] font-bold text-g900">${y}년 ${m+1}월</h2><button onclick="calNext()" class="w-10 h-10 rounded-full bg-g100 grid place-items-center text-g600 hover:bg-g200 text-[18px] font-bold">›</button></div>
<div class="grid grid-cols-7 gap-2 mb-2 text-center text-[14px] font-bold text-g400">${["일","월","화","수","목","금","토"].map(d=>`<div>${d}</div>`).join("")}</div>
<div class="grid grid-cols-7 gap-2">${cells}</div>
<div class="flex gap-4 mt-5 text-[13px] text-g500 flex-wrap"><span class="inline-flex items-center gap-1.5"><span class="w-3 h-3 rounded bg-blue-tint"></span>업로드 예정 (신청값 자동)</span><span class="inline-flex items-center gap-1.5"><span class="w-3 h-3 rounded bg-emerald-50 border border-emerald-200"></span>직접 추가한 일정</span></div></div></div>`;}
function calPrev(){if(S.calM==null){const d=new Date();S.calY=d.getFullYear();S.calM=d.getMonth();}S.calM--;if(S.calM<0){S.calM=11;S.calY--;}render();}
function calNext(){if(S.calM==null){const d=new Date();S.calY=d.getFullYear();S.calM=d.getMonth();}S.calM++;if(S.calM>11){S.calM=0;S.calY++;}render();}
function calForm(title,dateVal,titleVal,delId,saveArg){return `<div class="flex items-center justify-between mb-3"><h3 class="text-[18px] font-bold text-g900">${title}</h3><button onclick="closeModal()" class="w-8 h-8 rounded-full bg-g100 grid place-items-center text-g500">✕</button></div><label class="block text-[14px] font-bold text-g600 mb-1">날짜</label><input id="calDate" type="date" value="${dateVal}" class="${INPUT} mb-3"><label class="block text-[14px] font-bold text-g600 mb-1">일정 제목</label><input id="calTitle" value="${titleVal}" placeholder="예: 쇼잉 업로드, 콘티 마감" class="${INPUT} mb-4"><div class="flex gap-2">${delId?`<button onclick="calDelete('${delId}')" class="${BTN_GHOST} text-red-600 px-5">삭제</button>`:''}<button onclick="calSave(${saveArg})" class="${BTN} flex-1">저장</button></div>`;}
function calAdd(ds){toast("업로드 일정은 담당 매니저가 관리합니다");return;if(!S.activeCamp){toast("승인된 캠페인을 먼저 선택하세요");return;}modal(calForm("일정 추가",ds,"",null,"null"));}
function calEdit(id){toast("업로드 일정은 담당 매니저가 관리합니다");return;const c=S.activeCamp;const e=((c&&c.schedule)||[]).find(x=>x.id===id);if(!e)return;modal(calForm("일정 수정",e.date,esc(e.title),id,`'${id}'`));}
function calSave(id){const c=S.activeCamp;if(!c){toast("캠페인을 선택하세요");return;}const date=gv("calDate"),title=(gv("calTitle")||"").trim();if(!date||!title){toast("날짜와 제목을 입력하세요");return;}let sch=((c.schedule)||[]).slice();if(id){sch=sch.map(x=>x.id===id?{id:id,date:date,title:title}:x);}else{sch.push({id:"e"+Date.now(),date:date,title:title});}calPersist(c,sch,"일정이 저장되었습니다");}
function calDelete(id){const c=S.activeCamp;if(!c)return;calPersist(c,((c.schedule)||[]).filter(x=>x.id!==id),"일정이 삭제되었습니다");}
function calPersist(c,sch,msg){c.schedule=sch;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+c.id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({schedule:sch})}).then(r=>{if(!r.ok)toast("저장 실패");}).catch(()=>toast("저장 오류"));closeModal();toast(msg);render();}
function calEditAuto(campId){return;const a=(S.myCamps||[]).find(x=>String(x.id)===String(campId));if(!a)return;modal(`<div class="flex items-center justify-between mb-3"><h3 class="text-[18px] font-bold text-g900 break-all">${esc(a.brand_name)} 업로드 희망일</h3><button onclick="closeModal()" class="w-8 h-8 rounded-full bg-g100 grid place-items-center text-g500">✕</button></div><p class="text-[13px] text-g500 mb-3">신청 시 입력한 업로드 희망일입니다. 변경하면 캠페인 정보에 반영됩니다.</p><input id="calDate" type="date" value="${esc(a.preferred_date||'')}" class="${INPUT} mb-4"><button onclick="calSaveAuto('${campId}')" class="${BTN} w-full">업로드 희망일 변경</button>`);}
function calSaveAuto(campId){const d=gv("calDate");const a=(S.myCamps||[]).find(x=>String(x.id)===String(campId));if(!a){return;}fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+campId,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({preferred_date:d})}).then(r=>{if(r.ok){a.preferred_date=d;toast("업로드 희망일이 변경되었습니다");}else toast("변경 실패");closeModal();render();}).catch(()=>toast("오류"));}
/* ===== ADMIN ===== */
function genPw(){return "kn"+Math.random().toString(36).slice(2,7)+Math.floor(Math.random()*90+10);}
setInterval(function(){try{var ae=document.activeElement;if(ae&&(ae.tagName==="TEXTAREA"||ae.tagName==="INPUT")&&ae.value)return;if(S.role==="admin"){if(typeof loadApps==="function")loadApps();}else if(S.role==="customer"){if(typeof loadMyCamps==="function")loadMyCamps();}}catch(e){}},7000);function loadApps(){fetch(SUPA_URL+"/rest/v1/knollad_applications?select=*&order=created_at.desc",{headers:SH}).then(r=>r.json()).then(rows=>{ADM_ROWS=Array.isArray(rows)?rows:[];if(S.role==="cs")ADM_ROWS=ADM_ROWS.filter(function(a){return String(a.email||"").trim().toLowerCase()==="y-tribe@cnolad.com";});var sig=JSON.stringify((ADM_ROWS||[]).map(function(a){return [a.id,a.status,a.pay_status,(a.wf||{}).step,(a.notes||[]).length];}));if(sig!==S._admSig){S._admSig=sig;render();}else{if(S.view==="admin-dashboard")renderAdmRows();else if(S.view==="admin-members")renderMembers();}}).catch(()=>{const b=document.getElementById("admRows");if(b)b.innerHTML='<tr><td colspan="9" class="px-4 py-10 text-center text-g400">불러오기 실패</td></tr>';});}
function viewAdminList(){setTimeout(loadApps,30);return `<div class="p-8 md:p-10">${pageHeader("ADMIN","캠페인 관리","폼으로 접수된 실제 신청 데이터 · 승인 시 계정 자동 발급")}
<div class="grid grid-cols-2 md:grid-cols-5 gap-3 mb-6" id="admStats"></div>
<div class="mb-4" id="admMgrBar"></div>
<div class="${CARD} overflow-hidden"><div class="overflow-x-auto"><table class="w-full text-left min-w-[960px]"><thead><tr class="border-b border-g100 bg-g50">${["접수일","브랜드","담당자","이메일","연락처","채널 / 금액","상태","결제","처리"].map(h=>`<th class="px-4 py-3 text-[13px] font-bold text-g500 whitespace-nowrap">${h}</th>`).join("")}</tr></thead><tbody id="admRows"><tr><td colspan="9" class="px-4 py-10 text-center text-g400">불러오는 중…</td></tr></tbody></table></div></div></div>`;}
function admMgrList(){var s=[];(ADM_ROWS||[]).forEach(function(a){var m=a.manager||a.contact_name;if(m&&s.indexOf(m)<0)s.push(m);});return s;}function setAdmMgr(m){S.admMgr=m||null;renderAdmRows();}function admMgrBar(){var el=document.getElementById("admMgrBar");if(!el)return;var ms=admMgrList();if(ms.length<2){el.innerHTML="";return;}var cur=S.admMgr||"";el.innerHTML='<div class="flex items-center gap-2 flex-wrap"><span class="text-[13px] font-bold text-g500">담당자 필터</span><select onchange="setAdmMgr(this.value)" class="px-3 py-2 rounded-lg border border-g200 text-[14px] bg-white"><option value="">전체</option>'+ms.map(function(m){return '<option value="'+esc(m)+'"'+(cur===m?" selected":"")+'>'+esc(m)+'</option>';}).join('')+'</select></div>';}function renderAdmRows(){const b=document.getElementById("admRows");if(!b)return;admMgrBar();var rows=ADM_ROWS;if(S.admMgr){rows=rows.filter(function(a){return (a.manager||a.contact_name)===S.admMgr;});}
b.innerHTML=rows.length?rows.map(a=>{const chans=(a.channels||[]).map(c=>c.name).join(", ")||"-";const approved=a.status==="승인 완료";const isMember=ADM_ROWS.some(x=>x.email===a.email&&x.account_pw&&x.status==="승인 완료"&&String(x.id)!==String(a.id));return `<tr class="border-b border-g100 last:border-0 hover:bg-g50 align-top"><td class="px-4 py-3 text-[13px] text-g400 num">${(a.created_at||"").slice(0,10)}</td><td class="px-4 py-3 font-bold text-g900 text-[15px]">${esc(a.brand_name)}${holdBadge(a)}${!campSeen(a.id)?' <span class="text-[10px] font-bold text-white px-1.5 py-0.5 rounded-md align-middle" style="background:#10b981">N</span>':""}</td><td class="px-4 py-3 text-g700 text-[15px]">${esc(a.manager||a.contact_name)}</td><td class="px-4 py-3 text-g500 text-[14px]">${esc(a.email)}</td><td class="px-4 py-3 text-g500 text-[14px] num">${esc(a.phone)}</td><td class="px-4 py-3 text-[14px] max-w-[220px]"><div class="text-g700 truncate">${esc(chans)}</div><div class="text-blue font-bold num">${wonM(a.total_amount||0)}</div></td><td class="px-4 py-3">${statusBadge(a.status)}${approved&&a.account_pw?`<button onclick="showCreds('${esc(a.account_id||a.email)}','${esc(a.account_pw)}')" class="block mt-1 text-[12px] text-blue font-bold">계정/안내문</button>`:''}</td><td class="px-4 py-3">${statusBadge(a.pay_status||"결제 대기중")}${approved?`<div class="mt-1">${a.pay_status==="결제 완료"?`<button onclick="admSetPay('${a.id}','결제 대기중')" class="text-[11px] text-g500 font-bold">대기로</button>`:`<button onclick="admSetPay('${a.id}','결제 완료')" class="text-[11px] text-emerald-600 font-bold">결제완료 처리</button>`}</div>`:""}</td><td class="px-4 py-3"><div class="flex gap-1 flex-wrap"><button onclick="admView('${a.id}')" class="px-2.5 py-1.5 rounded-xl bg-blue-tint text-blue text-[12px] font-bold">보기</button>${approved?'':`<button onclick="admApprove('${a.id}','${esc(a.email)}')" class="px-2.5 py-1.5 rounded-xl text-[12px] font-bold" style="background:#3182F6;color:#fff">${isMember?"승인·기존회원":"승인"}</button>`}${approved?`<button onclick="openAdmWf('${a.id}')" class="px-2.5 py-1.5 rounded-xl bg-emerald-50 text-emerald-700 text-[12px] font-bold">워크플로우</button>`:''}${holdBtn(a)}<button onclick="admReject('${a.id}')" class="px-2.5 py-1.5 rounded-xl bg-red-50 text-red-600 text-[12px] font-bold">반려</button><button onclick="admDelete('${a.id}','${esc(a.brand_name)}')" class="px-2.5 py-1.5 rounded-xl text-[12px] font-bold" style="background:#191F28;color:#fff">삭제</button></div></td></tr>`;}).join(""):'<tr><td colspan="9" class="px-4 py-10 text-center text-g400">아직 접수된 신청이 없습니다. 폼에서 신청하면 여기에 표시됩니다.</td></tr>';
const s=document.getElementById("admStats");if(s){const c=k=>rows.filter(a=>a.status===k).length;s.innerHTML=[["전체 신청",rows.length],["검토 대기",c("검토 대기중")],["승인 완료",c("승인 완료")],["진행중",c("진행중")],["완료 캠페인",rows.filter(function(a){return a.wf&&a.wf.step>=7;}).length]].map(x=>`<div class="${CARD} p-5"><p class="text-[14px] text-g400 mb-1.5">${x[0]}</p><p class="font-display text-[30px] font-bold text-g900 num">${x[1]}</p></div>`).join("");}}
function admApprove(id,email){const a=ADM_ROWS.find(x=>String(x.id)===String(id))||{};const now=new Date().toISOString();fetch(SUPA_URL+"/rest/v1/knollad_members?email=eq."+encodeURIComponent(email)+"&select=password&limit=1",{headers:SH}).then(r=>r.json()).then(rows=>{const ex=rows&&rows[0];const pw=ex?ex.password:genPw();const doPatch=function(){fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({status:"승인 완료",account_id:email,account_pw:pw,approved_at:now,wf:{step:2,dataUrl:(a.files&&a.files[0]?a.files[0].url:null),dataLink:[a.material?"활용 소재: "+a.material:"",a.product_link?"제품 링크: "+a.product_link:"",a.concept?"희망 컨셉: "+a.concept:"",a.note?"요청사항: "+a.note:""].filter(Boolean).join(" / ")||"신청서에서 자료 전달 완료"}})}).then(r=>{if(r.ok){loadApps();if(ex){toast("기존 회원 승인 완료 · 계정 유지");}else{showCreds(email,pw);}}else toast("승인 실패 (권한)");}).catch(()=>toast("승인 실패"));};if(ex){doPatch();}else{fetch(SUPA_URL+"/rest/v1/knollad_members",{method:"POST",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({email:email,password:pw,contact_name:a.contact_name,brand_name:a.brand_name})}).then(function(){doPatch();}).catch(function(){doPatch();});}}).catch(()=>toast("승인 오류"));}
function holdBadge(a){return a.on_hold?' <span class="text-[10px] font-bold text-white px-1.5 py-0.5 rounded-md align-middle" style="background:#F59E0B">보류</span>':'';}function holdBtn(a){return '<button data-hid="'+a.id+'" data-hv="'+(a.on_hold?'0':'1')+'" onclick="admHold(this.dataset.hid,this.dataset.hv)" class="px-2.5 py-1.5 rounded-xl text-[12px] font-bold" style="background:#FEF3C7;color:#B45309">'+(a.on_hold?'보류해제':'보류')+'</button>';}function admHold(id,hv){var val=(hv==="1");fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({on_hold:val})}).then(function(r){if(r.ok){toast(val?"보류 처리됨":"보류 해제됨");loadApps();}else toast("처리 실패");}).catch(function(){toast("처리 실패");});}function admReject(id){window._rejId=id;modal('<div class="flex items-center justify-between mb-3"><h3 class="text-[18px] font-bold text-g900">캠페인 반려</h3><button onclick="closeModal()" class="w-8 h-8 rounded-full bg-g100 grid place-items-center text-g500">✕</button></div><p class="text-[14px] text-g500 mb-2">반려 사유를 입력하세요. 신청한 회원에게 팝업으로 표시됩니다.</p><textarea id="rejReason" rows="4" placeholder="예: 요청하신 채널이 현재 운영 중단 상태입니다." class="'+INPUT+' resize-none"></textarea><div class="flex gap-2 mt-3"><button onclick="admRejectConfirm()" class="'+BTN+' flex-1" style="background:#DC2626">반려 처리</button><button onclick="closeModal()" class="'+BTN_GHOST+' px-5">취소</button></div>');}function admRejectConfirm(){var id=window._rejId;if(!id)return;var reason=(gv("rejReason")||"").trim();if(!reason){toast("반려 사유를 입력해주세요");return;}fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({status:"반려",reject_reason:reason})}).then(function(r){if(r.ok){try{var _ra=ADM_ROWS.find(function(x){return String(x.id)===String(id);});if(_ra&&_ra.email&&!(_ra.manager&&String(_ra.manager).trim())&&typeof notifyEmail==="function")notifyEmail(_ra.email,"[크놀AD] 캠페인 반려 안내",emailTpl(_ra,"[크놀AD] 캠페인 반려 안내","신청하신 캠페인이 반려되었습니다.<br><br><b>반려 사유</b><br>"+String(reason).replace(/</g,"&lt;")+"<br><br>확인 후 다시 신청해 주세요."));}catch(_ee){}toast("반려 처리됨");closeModal();loadApps();}else toast("처리 실패");}).catch(function(){toast("처리 실패");});}function admUpdate(id,status){fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({status})}).then(r=>{if(r.ok){toast(status+" 처리됨");loadApps();}else toast("처리 실패");}).catch(()=>toast("처리 실패"));}
function admDelete(id,brand){modal(`<div class="text-center"><div class="w-14 h-14 rounded-full bg-red-50 grid place-items-center mx-auto mb-4"><i data-lucide="trash-2" class="w-7 h-7 text-red-500"></i></div><h3 class="text-[19px] font-bold text-g900 mb-1">캠페인을 삭제할까요?</h3><p class="text-g600 text-[15px] font-bold mb-1">${esc(brand)}</p><p class="text-[13px] text-red-500 mb-5 leading-relaxed">삭제하면 <b>고객 캠페인 현황에서도 사라지며</b><br>되돌릴 수 없습니다. 정말 삭제하시겠습니까?</p></div><div class="flex gap-2"><button onclick="closeModal()" class="${BTN_GHOST} flex-1">취소</button><button onclick="admDeleteConfirm('${id}')" class="flex-1 inline-flex items-center justify-center gap-2 px-7 py-4 rounded-[20px] font-bold text-[17px] active:scale-[0.97]" style="background:#EF4444;color:#fff">최종 삭제</button></div>`);}
