function sendStepMail(id){const a=ADM_ROWS.find(x=>String(x.id)===String(id));if(!a)return;if(!a.email){toast("고객 이메일이 없습니다");return;}const wf=a.wf||{step:2};const stages=["문의 접수","자료 공유","콘티 작성","콘티 컨펌","영상 제작","영상 컨펌","완료 · 리포트"];const lbl=stages[Math.min(wf.step-1,6)];const bn=a.brand_name||"캠페인";const subj="[크놀AD] "+bn+" 진행 알림 · "+lbl;const html="<div style=\"font-family:sans-serif;font-size:15px;color:#191F28\">안녕하세요, <b>"+esc(bn)+"</b> 캠페인 담당자님.<br><br>현재 진행 단계: <b>"+esc(lbl)+"</b><br>크놀AD에서 진행 상황을 확인해 주세요.<br><br><a href=\"https://www.cnolad.com\">https://www.cnolad.com</a></div>";toast("알림 메일 발송 중…");fetch(SUPA_URL+"/functions/v1/notify-step",{method:"POST",headers:{"Content-Type":"application/json",apikey:SUPA_KEY,Authorization:"Bearer "+SUPA_KEY},body:JSON.stringify({to:a.email,subject:subj,html:html})}).then(r=>r.json()).then(res=>{if(res&&res.ok)toast("고객("+a.email+")에게 알림 발송 완료");else toast("발송 실패 · Supabase에 RESEND_API_KEY 설정 필요");}).catch(()=>toast("발송 오류"));}
