function admWfSave(id,patch,msg){const a=ADM_ROWS.find(x=>String(x.id)===String(id));const wf=Object.assign({},(a&&a.wf)||{step:2},patch);fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({wf})}).then(r=>{if(r.ok){if(a)a.wf=wf;try{if(a&&a.email&&!(a.manager&&String(a.manager).trim())&&typeof notifyEmail==="function"){var _es,_eb;if(patch.conti){_es="[크놀AD] 콘티가 도착했습니다";_eb="요청하신 캠페인의 콘티가 등록되었습니다. 사이트에 로그인하여 확인 후 컨펌해 주세요.";}else if(patch.video){_es="[크놀AD] 영상이 도착했습니다";_eb="캠페인 영상이 등록되었습니다. 사이트에서 확인 후 컨펌해 주세요.";}else if(patch.urls||patch.step===7){_es="[크놀AD] 콘텐츠 업로드 완료";_eb="콘텐츠 업로드가 완료되었습니다. 리포트 탭에서 성과를 확인하실 수 있습니다.";}else{_es="[크놀AD] 캠페인 진행 상황 업데이트";_eb="캠페인 진행 상황이 업데이트되었습니다.";}notifyEmail(a.email,_es,emailTpl(a,_es,_eb));}}catch(_ee){}toast(msg||"저장되었습니다");closeModal();loadApps();}else toast("저장 실패");}).catch(()=>toast("저장 오류"));}
function wfSend(){var c=S.activeCamp;if(!c)return;var t=(gv("wfMsgInput")||"").trim();var fi=document.getElementById("wfMsgFile");var files=(fi&&fi.files)?Array.prototype.slice.call(fi.files):[];if(!t&&!files.length){toast("메시지 또는 파일을 입력하세요");return;}var notes=(c.notes||[]).slice();if(t){notes.push({who:(S.cust&&S.cust.name)||"고객",role:"cust",text:t,at:new Date().toISOString()});}var i=0;if(files.length)toast("전송 중…");(function nx(){if(i>=files.length){c.notes=notes;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+c.id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({notes:notes})}).catch(function(){});toast("메시지를 보냈습니다");render();return;}var f=files[i];var path=Date.now()+"_"+i+"_"+(f.name||"file").replace(/[^\w.\-]/g,"_");fetch(SUPA_URL+"/storage/v1/object/deliverables/"+encodeURIComponent(path),{method:"POST",headers:{apikey:SUPA_KEY,Authorization:"Bearer "+SUPA_KEY,"Content-Type":f.type||"application/octet-stream","x-upsert":"true"},body:f}).then(function(r){if(r.ok){notes.push({who:(S.cust&&S.cust.name)||"고객",role:"cust",text:"📎 "+f.name,fileUrl:SUPA_URL+"/storage/v1/object/public/deliverables/"+encodeURIComponent(path),at:new Date().toISOString()});}i++;nx();}).catch(function(){i++;nx();});})();}function admSend(id){var a=ADM_ROWS.find(function(x){return String(x.id)===String(id);});if(!a)return;var t=(gv("admMsgInput")||"").trim();var fi=document.getElementById("admMsgFile");var files=(fi&&fi.files)?Array.prototype.slice.call(fi.files):[];if(!t&&!files.length){toast("메시지 또는 파일을 입력하세요");return;}var notes=(a.notes||[]).slice();if(t){notes.push({who:"크놀AD",role:"knoll",text:t,at:new Date().toISOString()});}var i=0;if(files.length)toast("전송 중…");(function nx(){if(i>=files.length){a.notes=notes;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({notes:notes})}).then(function(r){if(r.ok){toast("메시지를 보냈습니다");loadApps();}else toast("저장 실패");}).catch(function(){toast("오류");});return;}var f=files[i];var path=Date.now()+"_"+i+"_"+(f.name||"file").replace(/[^\w.\-]/g,"_");fetch(SUPA_URL+"/storage/v1/object/deliverables/"+encodeURIComponent(path),{method:"POST",headers:{apikey:SUPA_KEY,Authorization:"Bearer "+SUPA_KEY,"Content-Type":f.type||"application/octet-stream","x-upsert":"true"},body:f}).then(function(r){if(r.ok){notes.push({who:"크놀AD",role:"knoll",text:"📎 "+f.name,fileUrl:SUPA_URL+"/storage/v1/object/public/deliverables/"+encodeURIComponent(path),at:new Date().toISOString()});}i++;nx();}).catch(function(){i++;nx();});})();}function wfMsgFilesM(){var c=S.activeCamp;if(!c)return;var fi=document.getElementById("wfMsgFile");if(!fi||!fi.files||!fi.files.length){toast("파일을 선택하세요");return;}var files=Array.prototype.slice.call(fi.files);var notes=(c.notes||[]).slice();var i=0;toast("파일 업로드 중…");(function nx(){if(i>=files.length){c.notes=notes;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+c.id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({notes:notes})}).catch(function(){});toast("파일을 보냈습니다");render();return;}var f=files[i];var path=Date.now()+"_"+i+"_"+(f.name||"file").replace(/[^\w.\-]/g,"_");fetch(SUPA_URL+"/storage/v1/object/deliverables/"+encodeURIComponent(path),{method:"POST",headers:{apikey:SUPA_KEY,Authorization:"Bearer "+SUPA_KEY,"Content-Type":f.type||"application/octet-stream","x-upsert":"true"},body:f}).then(function(r){if(r.ok){notes.push({who:(S.cust&&S.cust.name)||"고객",role:"cust",text:"📎 "+f.name,fileUrl:SUPA_URL+"/storage/v1/object/public/deliverables/"+encodeURIComponent(path),at:new Date().toISOString()});}i++;nx();}).catch(function(){i++;nx();});})();}function admMsgFilesM(id){var a=ADM_ROWS.find(function(x){return String(x.id)===String(id);});if(!a)return;var fi=document.getElementById("admMsgFile");if(!fi||!fi.files||!fi.files.length){toast("파일을 선택하세요");return;}var files=Array.prototype.slice.call(fi.files);var notes=(a.notes||[]).slice();var i=0;toast("파일 업로드 중…");(function nx(){if(i>=files.length){a.notes=notes;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({notes:notes})}).then(function(r){if(r.ok){toast("파일을 보냈습니다");loadApps();}else toast("저장 실패");}).catch(function(){toast("오류");});return;}var f=files[i];var path=Date.now()+"_"+i+"_"+(f.name||"file").replace(/[^\w.\-]/g,"_");fetch(SUPA_URL+"/storage/v1/object/deliverables/"+encodeURIComponent(path),{method:"POST",headers:{apikey:SUPA_KEY,Authorization:"Bearer "+SUPA_KEY,"Content-Type":f.type||"application/octet-stream","x-upsert":"true"},body:f}).then(function(r){if(r.ok){notes.push({who:"크놀AD",role:"knoll",text:"📎 "+f.name,fileUrl:SUPA_URL+"/storage/v1/object/public/deliverables/"+encodeURIComponent(path),at:new Date().toISOString()});}i++;nx();}).catch(function(){i++;nx();});})();}function uploadMany(inputId,cb){var inp=document.getElementById(inputId);var files=(inp&&inp.files)?[].slice.call(inp.files):[];if(!files.length){cb([]);return;}var urls=[],i=0;toast("파일 업로드 중…");function nx(){if(i>=files.length){cb(urls);return;}var f=files[i++];var path=Date.now()+"_"+i+"_"+(f.name||"file").replace(/[^A-Za-z0-9_.-]/g,"_");fetch(SUPA_URL+"/storage/v1/object/deliverables/"+encodeURIComponent(path),{method:"POST",headers:{apikey:SUPA_KEY,Authorization:"Bearer "+SUPA_KEY,"Content-Type":f.type||"application/octet-stream","x-upsert":"true"},body:f}).then(function(r){if(r.ok)urls.push(SUPA_URL+"/storage/v1/object/public/deliverables/"+encodeURIComponent(path));nx();}).catch(function(){nx();});}nx();}
function uploadToStorage(inputId,cb){let inp=document.getElementById(inputId);if(inp&&inp.tagName!=="INPUT"&&typeof zoneInput==="function"){inp=zoneInput(inputId)||inp;}const f=inp&&inp.files&&inp.files[0];if(!f){cb(null);return;}if(f.size>2147483648){toast("⚠️ 파일이 2GB를 초과해 업로드할 수 없습니다 ("+(f.size/1073741824).toFixed(1)+"GB) · 링크로 전달해주세요");cb(null);return;}const path=Date.now()+"_"+(f.name||"file").replace(/[^\w.\-]/g,"_");toast("파일 업로드 중…");fetch(SUPA_URL+"/storage/v1/object/deliverables/"+encodeURIComponent(path),{method:"POST",headers:{apikey:SUPA_KEY,Authorization:"Bearer "+SUPA_KEY,"Content-Type":f.type||"application/octet-stream","x-upsert":"true"},body:f}).then(r=>{if(r.ok)cb(SUPA_URL+"/storage/v1/object/public/deliverables/"+encodeURIComponent(path));else{toast("파일 업로드 실패");cb(null);}}).catch(()=>{toast("업로드 오류");cb(null);});}
function admPushNote(id,note){var a=ADM_ROWS.find(function(x){return String(x.id)===String(id);});var notes=((a&&a.notes)||[]).slice();notes.push(note);fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({notes:notes})}).then(function(){if(a)a.notes=notes;}).catch(function(){});}
function admDeliverConti(id){const title=(gv("admContiTitle")||"").trim();const text=(gv("admContiText")||"").trim();const link=(gv("admConti")||"").trim();const fi=document.getElementById("admContiFile");const hasF=fi&&fi.files&&fi.files.length;if(!title&&!text&&!link&&!hasF){toast("제목·내용·링크·파일 중 하나는 입력하세요");return;}const save=function(fu){admWfSave(id,{conti:{title:title||null,text:text||null,link:link||null,fileUrl:fu||null},step:4,note:null},"콘티가 전달되었습니다");admPushNote(id,{who:"크놀AD",role:"knoll",title:"📋 콘티 전달"+(title?" · "+title:""),text:text||null,link:link||null,fileUrl:fu||null,at:new Date().toISOString()});};if(hasF){uploadToStorage("admContiFile",function(u){if(!u){toast("⚠️ 파일 업로드 실패 · 콘티 전달을 중단했습니다. 용량(최대 2GB) 확인 후 다시 시도하거나 링크로 전달해주세요");return;}save(u);});}else save(null);}
function admDeliverVideo(id){const title=(gv("admVideoTitle")||"").trim();const text=(gv("admVideoText")||"").trim();const link=(gv("admVideo")||"").trim();const fi=document.getElementById("admVideoFile");const hasF=fi&&fi.files&&fi.files.length;if(!title&&!text&&!link&&!hasF){toast("제목·내용·링크·파일 중 하나는 입력하세요");return;}const save=function(fu){admWfSave(id,{video:{title:title||null,text:text||null,link:link||null,fileUrl:fu||null},step:6,note:null},"영상이 전달되었습니다");admPushNote(id,{who:"크놀AD",role:"knoll",title:"🎬 영상 전달"+(title?" · "+title:""),text:text||null,link:link||null,fileUrl:fu||null,at:new Date().toISOString()});};if(hasF){uploadToStorage("admVideoFile",function(u){if(!u){toast("⚠️ 파일 업로드 실패 · 영상 전달을 중단했습니다. 용량(최대 2GB) 확인 후 다시 시도하거나 링크로 전달해주세요");return;}save(u);});}else save(null);}
function admSaveUrls(id){const urls={yt:(gv("admYt")||"").trim(),ig:(gv("admIg")||"").trim(),tt:(gv("admTt")||"").trim()};admWfSave(id,{urls,step:7},"업로드 URL이 저장되었습니다");}
function admSetPay(id,status){if(!confirm("결제 상태를 '"+status+"'(으)로 변경할까요?"))return;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({pay_status:status})}).then(r=>{if(r.ok){toast("결제 상태: "+status);closeModal();loadApps();}else toast("처리 실패");}).catch(()=>toast("오류"));}
function admConfirmPay(id){if(!confirm("결제 완료로 처리할까요?\n고객 화면에 결제 완료로 표시됩니다."))return;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({pay_status:"결제 완료"})}).then(r=>{if(r.ok){try{var _pa=ADM_ROWS.find(function(x){return String(x.id)===String(id);});if(_pa&&_pa.email&&!(_pa.manager&&String(_pa.manager).trim())&&typeof notifyEmail==="function")notifyEmail(_pa.email,"[크놀AD] 정산 입금 확인 완료",emailTpl(_pa,"[크놀AD] 정산 입금 확인 완료","정산 입금이 확인되어 결제 완료 처리되었습니다. 이용해 주셔서 감사합니다."));}catch(_ee){}toast("결제 완료 처리됨");closeModal();loadApps();}else toast("처리 실패");}).catch(()=>toast("오류"));}
