const bars=months.map(function(k){var v=monthly[k]||0;var h=Math.round((v/maxM)*150);var mm=parseInt(k.slice(5),10)+"월";return `<div class="flex flex-col items-center gap-2 w-16 flex-shrink-0"><div class="text-[12px] font-bold text-g500 num">${v?(Math.round(v/10000).toLocaleString()+"만"):""}</div><div class="w-11 rounded-t-lg" style="height:${h}px;min-height:3px;background:${v?"linear-gradient(180deg,#3182F6,#1B64DA)":"#E5E8EB"}"></div><div class="text-[13px] font-bold text-g600 whitespace-nowrap">${mm}</div></div>`;}).join("");
