function exportSalesCSV(){const camps=(ADM_ROWS||[]).filter(function(a){return a.status==="승인 완료";});if(!camps.length){toast("내보낼 데이터가 없습니다");return;}const q=function(v){return '"'+String(v==null?"":v).replace(/"/g,'""')+'"';};const head=["접수일","승인일","브랜드","담당자","이메일","채널","공급가액(원)","결제상태"];const rows=camps.map(function(a){return [(a.created_at||"").slice(0,10),(a.approved_at||"").slice(0,10),a.brand_name,a.contact_name,a.email,(a.channels||[]).map(function(c){return c.name;}).join(" / "),((a.total_amount||0)-(a.discount||0))*10000,a.pay_status||"결제 대기중"].map(q).join(",");});const csv="﻿"+head.map(q).join(",")+"\n"+rows.join("\n");const blob=new Blob([csv],{type:"text/csv;charset=utf-8;"});const url=URL.createObjectURL(blob);const el=document.createElement("a");el.href=url;el.download="크놀AD_매출분석_"+new Date().toISOString().slice(0,10)+".csv";document.body.appendChild(el);el.click();document.body.removeChild(el);URL.revokeObjectURL(url);toast("엑셀(CSV) 다운로드 완료");}
