function admCalPersist(a,sch){a.schedule=sch;fetch(SUPA_URL+'/rest/v1/knollad_applications?id=eq.'+a.id,{method:'PATCH',headers:Object.assign({'Content-Type':'application/json','Prefer':'return=minimal'},SH),body:JSON.stringify({schedule:sch})}).then(function(r){if(!r.ok)toast('저장 실패');else toast('일정 저장됨');});closeModal();}function admCalSave(id){var a=(ADM_ROWS||[]).find(function(x){return String(x.id)===String(id);});if(!a)return;var date=gv('acDate'),title=(gv('acTitle')||'').trim();if(!date||!title){toast('날짜와 제목을 입력하세요');return;}var sch=((a.schedule)||[]).slice();sch.push({id:'e'+Date.now(),date:date,title:title});admCalPersist(a,sch);}function admCalDel(id,eid){var a=(ADM_ROWS||[]).find(function(x){return String(x.id)===String(id);});if(!a)return;admCalPersist(a,((a.schedule)||[]).filter(function(x){return x.id!==eid;}));}function admCalPick(){var cs=(ADM_ROWS||[]).filter(function(a){return a.status==="승인 완료";});var list=cs.length?cs.map(function(a){return '<button onclick="closeModal();admCalOpen(\''+a.id+'\')" class="w-full flex items-center justify-between py-3 px-3 border-b border-g100 hover:bg-g50 text-left"><span class="text-[15px] font-bold text-g900">'+esc(a.brand_name)+(a.manager?' · '+esc(a.manager):'')+'</span><span class="text-[13px] text-blue font-bold">일정 관리 ›</span></button>';}).join(''):'<p class="text-g400 text-[14px] py-4 text-center">승인 완료된 캠페인이 없습니다</p>';modal('<div class="flex items-center justify-between mb-3"><h3 class="text-[18px] font-bold text-g900">일정을 추가할 캠페인 선택</h3><button onclick="closeModal()" class="w-8 h-8 rounded-full bg-g100 grid place-items-center text-g500">✕</button></div><div class="max-h-[60vh] overflow-y-auto">'+list+'</div>');}function admCalOpen(id,editId){var a=(ADM_ROWS||[]).find(function(x){return String(x.id)===String(id);});if(!a)return;var sch=(a.schedule||[]);var ed=editId?sch.find(function(x){return String(x.id)===String(editId);}):null;var list=sch.length?sch.map(function(e){var _ing=ed&&String(e.id)===String(editId);return '<div class="flex items-center justify-between py-2 border-b border-g100'+(_ing?' bg-blue-soft rounded-lg px-2':'')+'"><div class="text-[14px] text-g800"><b>'+esc(e.date)+'</b> · '+esc(e.title)+'</div><div class="flex items-center gap-3"><button onclick="admCalOpen(\''+id+'\',\''+e.id+'\')" class="text-blue text-[13px] font-bold">수정</button><button onclick="admCalDel(\''+id+'\',\''+e.id+'\')" class="text-red-600 text-[13px] font-bold">삭제</button></div></div>';}).join(''):'<p class="text-g400 text-[14px] py-2">등록된 일정이 없습니다</p>';var _btn=ed?'<button onclick="admCalUpdate(\''+id+'\',\''+editId+'\')" class="'+BTN+' w-full">수정 저장</button><button onclick="admCalOpen(\''+id+'\')" class="w-full text-center text-g500 text-[13px] font-bold mt-2 py-1">취소</button>':'<button onclick="admCalSave(\''+id+'\')" class="'+BTN+' w-full">+ 일정 추가</button>';modal('<div class="flex items-center justify-between mb-3"><h3 class="text-[18px] font-bold text-g900 break-all">'+esc(a.brand_name)+' 업로드 일정</h3><button onclick="closeModal()" class="w-8 h-8 rounded-full bg-g100 grid place-items-center text-g500">✕</button></div>'+list+'<div class="mt-3 pt-3 border-t border-g100"><p class="text-[13px] font-bold text-g600 mb-2">'+(ed?'일정 수정':'새 일정 추가')+'</p><input id="acDate" type="date" class="'+INPUT+' mb-2"><input id="acTitle" placeholder="일정 제목 (예: 쇼잉 업로드)" class="'+INPUT+' mb-2">'+_btn+'</div>','max-w-lg');if(ed){var _d=document.getElementById('acDate');if(_d)_d.value=ed.date;var _t=document.getElementById('acTitle');if(_t)_t.value=ed.title;}}
function admCalUpdate(id,eid){var a=(ADM_ROWS||[]).find(function(x){return String(x.id)===String(id);});if(!a)return;var date=gv('acDate'),title=(gv('acTitle')||'').trim();if(!date||!title){toast('날짜와 제목을 입력하세요');return;}var sch=((a.schedule)||[]).map(function(x){return String(x.id)===String(eid)?{id:x.id,date:date,title:title}:x;});admCalPersist(a,sch);}
